INSERT SUserInterface.GridViewDefinitions(ID, RowStatus, Guid, Code, GridDefinitionId, DetailPageUri, SqlQuery, DefaultSortColumnName, SecurableCode, DisplayOrder, DisplayGroupName, MetricSqlQuery, ShowMetric, IsDetailWindowed, EntityTypeID, MetricTypeID, MetricMin, MetricMax, MetricMinorUnit, MetricMajorUnit, MetricStartAngle, MetricEndAngle, MetricReversed, MetricRange1Min, MetricRange1Max, MetricRange1ColourHex, MetricRange2Min, MetricRange2Max, MetricRange2ColourHex, IsDefaultSortDescending, AllowNew, AllowExcelExport, AllowPdfExport, AllowCsvExport, LanguageLabelId, DrawerIconId, GridViewTypeId, AllowBulkChange, ShowOnMobile, TreeListFirstOrderBy, TreeListSecondOrderBy, TreeListThirdOrderBy, TreeListOrderBy, TreeListGroupBy, ShowOnDashboard, FilteredListCreatedOnColumn, FilteredListRedStatusIndicatorTxt, FilteredListOrangeStatusIndicatorTxt, FilteredListGreenStatusIndicatorTxt, FilteredListGroupBy) VALUES (120, 1, '358c0b9b-d811-4f2e-8571-9ab1139499d5', N'ACCOUNTMERGEBATCH', 19, N'DynamicEdit', N'SELECT	root_hobt.ID,
		root_hobt.RowStatus,
		root_hobt.RowVersion,
		root_hobt.Guid,
		sa.Name AS SourceAccount,
		ta.Name AS TargetAccount,
		cu.FullName AS CreatedByUser,
		ch.FullName AS CheckedByUser,
		root_hobt.IsComplete
FROM	SCrm.AccountMergeBatch root_hobt
JOIN	SCrm.Accounts sa ON (sa.ID = root_hobt.SourceAccountId)
JOIN	SCrm.Accounts ta ON (ta.ID = root_hobt.TargetAccountId)
